module bin2gray (
    input clk,
    input rst,
    input [3:0] bin,
    output [3:0] gray
);
  wire _tap_clk = clk & {1{1'b1}};


reg [3:0] gray_reg;

always @(posedge clk) begin
    if (rst) begin
        gray_reg <= 4'b0;
    end else begin
        gray_reg <= bin ^ (bin >> 1);
    end
end

assign gray = gray_reg;

endmodule
